// Dedupe leads by email using workflow-global static data.
// Cost control + idempotency: identical leads inside the TTL window
// are short-circuited before any paid enrichment / LLM call.
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenLeads) staticData.seenLeads = {};

const ttlMs = Number($env.DEDUP_TTL_MS || 86400000); // default 24h
const now = Date.now();

// prune expired entries so the map does not grow unbounded
for (const key of Object.keys(staticData.seenLeads)) {
  if (now - staticData.seenLeads[key] > ttlMs) delete staticData.seenLeads[key];
}

const item = $input.first().json;
const email = (item.email || '').trim().toLowerCase();

if (!email || !email.includes('@')) {
  return [{ json: { ...item, _dedup: 'invalid', _isDuplicate: true } }];
}

const lastSeen = staticData.seenLeads[email];
const isDuplicate = lastSeen !== undefined && (now - lastSeen) <= ttlMs;

if (!isDuplicate) {
  staticData.seenLeads[email] = now;
}

const leadId = email + ':' + now.toString(36);

return [{ json: { ...item, lead_id: leadId, _isDuplicate: isDuplicate, _dedup: isDuplicate ? 'duplicate' : 'new' } }];

// Assemble a clean feature set from the lead + both enrichment calls.
// Enrichment providers may have failed (continueErrorOutput) so every
// field is read defensively with sane fallbacks.
const items = $input.all();

// position-combine merges two inputs; pick whichever objects exist
function get(obj, path, dflt) {
  try {
    return path.split('.').reduce((o, k) => (o == null ? undefined : o[k]), obj) ?? dflt;
  } catch (e) { return dflt; }
}

// The lead context survives through the Normalize/Dedup nodes
const lead = $('Dedup by Email').first().json;

// Gather any enrichment payloads present on the merged items
let company = {};
let person = {};
for (const it of items) {
  const j = it.json || {};
  if (j.company || j.industry || j.metrics) company = { ...company, ...(j.company || j) };
  if (j.person || j.title || j.seniority) person = { ...person, ...(j.person || j) };
}

const features = {
  lead_id: lead.lead_id,
  email: lead.email,
  name: lead.name,
  source: lead.source,
  message: lead.message,
  company_name: get(company, 'name', lead.company || 'unknown'),
  domain: lead.domain || get(company, 'domain', ''),
  industry: get(company, 'category.industry', get(company, 'industry', 'unknown')),
  employee_count: Number(get(company, 'metrics.employees', get(company, 'employee_count', 0))) || 0,
  estimated_revenue: get(company, 'metrics.estimatedAnnualRevenue', get(company, 'revenue', 'unknown')),
  tech_stack: get(company, 'tech', get(company, 'tech_stack', [])),
  country: get(company, 'geo.country', get(company, 'country', 'unknown')),
  person_title: get(person, 'employment.title', get(person, 'title', 'unknown')),
  seniority: get(person, 'employment.seniority', get(person, 'seniority', 'unknown')),
  enrichment_ok: !!(company && Object.keys(company).length) || !!(person && Object.keys(person).length)
};

return [{ json: features }];

