// Parse the LLM JSON, clamp the score, derive the tier deterministically.
const features = $('Build Feature Set').first().json;
const resp = $input.first().json;

let parsed = {};
try {
  const raw = resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content;
  parsed = typeof raw === 'string' ? JSON.parse(raw) : (raw || {});
} catch (e) {
  parsed = {};
}

let score = Number(parsed.fit_score);
if (!Number.isFinite(score)) score = 0;
score = Math.max(0, Math.min(100, Math.round(score)));

let tier = 'cold';
if (score >= 80) tier = 'hot';
else if (score >= 50) tier = 'warm';

return [{
  json: {
    ...features,
    fit_score: score,
    tier,
    reasons: Array.isArray(parsed.reasons) ? parsed.reasons : [],
    persona: parsed.persona || 'unknown',
    personalized_opener: parsed.personalized_opener || '',
    recommended_sequence: parsed.recommended_sequence || 'default',
    scored_at: new Date().toISOString()
  }
}];

// Build the final result object + an audit record.
const j = $input.first().json;

const actionByTier = {
  hot: 'crm_deal+slack+draft_email',
  warm: 'nurture_sequence',
  cold: 'logged_low_priority'
};

const result = {
  lead_id: j.lead_id,
  email: j.email,
  tier: j.tier,
  fit_score: j.fit_score,
  persona: j.persona,
  action: actionByTier[j.tier] || 'none',
  recommended_sequence: j.recommended_sequence,
  status: 'processed'
};

const audit = {
  ...result,
  reasons: j.reasons,
  enrichment_ok: j.enrichment_ok,
  company_name: j.company_name,
  industry: j.industry,
  employee_count: j.employee_count,
  source: j.source,
  scored_at: j.scored_at,
  audited_at: new Date().toISOString()
};

return [{ json: { result, audit } }];
